var htmlparser = require('htmlparser2');

var content = 'This readme causes an error <p> text  <h1> more text (</p>)';
var headers = [], grabbing = [], text = [];

var parser = new htmlparser.Parser({
    onopentag: function(name, attr) {
        if (grabbing[grabbing.length - 1] === 'pre') return;
        if (name === 'pre' || /h\d/.test(name)) {
            grabbing.push(name);
        }
    },
    ontext: function(text_) {
        if (grabbing.length === 0 || grabbing[grabbing.length - 1] === 'pre') return;
        text.push(text_);
        console.log('TEXT for ' + grabbing[grabbing.length - 1] + ':', JSON.stringify(text_));
    },
    onclosetag: function(name) {
        if (grabbing.length === 0) return;
        if (grabbing[grabbing.length - 1] === name) {
            var tag = grabbing.pop();
            headers.push({text: text.slice(), tag: tag});
            console.log('HEADER done for ' + tag + ', text:', JSON.stringify(text));
            text = [];
        }
    },
}, {decodeEntities: true});

parser.write(content);
parser.end();
console.log('Final headers:', JSON.stringify(headers, null, 2));
"

